const events = $input.all();
const results = [];
for (const item of events) {
  const e = item.json;
  results.push({
    json: {
      event_id: e.id || '',
      event_date: new Date().toISOString().split('T')[0],
      summary: e.summary || '',
      start_time: e.start?.dateTime || e.start?.date || '',
      end_time: e.end?.dateTime || e.end?.date || '',
      attendees: (e.attendees || []).map(a => a.email).join(','),
      location: e.location || '',
      calendar_id: 'primary'
    }
  });
}
return results.length > 0 ? results : [{ json: { message: 'No events today' } }];

const events = $input.all().map(i => i.json);
const now = new Date();
// Find next event
const upcoming = events.filter(e => new Date(e.start?.dateTime || e.start?.date) > now);
if (upcoming.length === 0) return [{ json: { message: 'No upcoming meetings in next 24h' } }];
const next = upcoming[0];
return [{ json: { next_meeting_summary: next.summary || '', next_meeting_start: next.start?.dateTime || next.start?.date, next_meeting_end: next.end?.dateTime || next.end?.date, next_meeting_attendees: (next.attendees || []).map(a => a.email).join(','), next_meeting_location: next.location || '', total_upcoming: upcoming.length } }];

const events = $input.all().map(i => i.json);
const today = new Date();
const startOfDay = new Date(today.getFullYear(), today.getMonth(), today.getDate(), 8, 0);
const endOfDay = new Date(today.getFullYear(), today.getMonth(), today.getDate(), 18, 0);

// Build busy slots
const busy = events.filter(e => e.start?.dateTime).map(e => ({
  start: new Date(e.start.dateTime),
  end: new Date(e.end.dateTime)
})).sort((a, b) => a.start - b.start);

// Find free slots (minimum 30 min)
const free = [];
let cursor = startOfDay;
for (const slot of busy) {
  if (slot.start > cursor) {
    const gap = (slot.start - cursor) / 60000;
    if (gap >= 30) free.push({ from: cursor.toISOString(), to: slot.start.toISOString(), minutes: Math.round(gap) });
  }
  if (slot.end > cursor) cursor = slot.end;
}
if (endOfDay > cursor) {
  const gap = (endOfDay - cursor) / 60000;
  if (gap >= 30) free.push({ from: cursor.toISOString(), to: endOfDay.toISOString(), minutes: Math.round(gap) });
}

return [{ json: { availability_windows: free, total_free_slots: free.length, total_free_minutes: free.reduce((s, f) => s + f.minutes, 0) } }];

const raw = $input.first().json.response || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  parsed = { create_event: false, reason: 'Could not parse AI response' };
}
return [{ json: parsed }];
